diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 76234ccfdcff..0aa3bb376324 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1862,6 +1862,7 @@ static Instruction *foldSubOfMinMax(BinaryOperator &I,
   return nullptr;
 }

+
 Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
   if (Value *V = simplifySubInst(I.getOperand(0), I.getOperand(1),
                                  I.hasNoSignedWrap(), I.hasNoUnsignedWrap(),
@@ -2084,7 +2085,7 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
       return BinaryOperator::CreateNeg(Builder.CreateXor(A, B));
   }

-  // (sub (or A, B), (xor A, B)) --> (and A, B)
+  // (sub (or A, B) (xor A, B)) --> (and A, B)
   {
     Value *A, *B;
     if (match(Op1, m_Xor(m_Value(A), m_Value(B))) &&
@@ -2257,6 +2258,28 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
       return BinaryOperator::CreateAnd(Op0, ConstantInt::get(Ty, ~(*AndC)));
   }

+  // C - ((C2 - X) & Mask) --> (X & Mask) + (C - (C2 & Mask))
+  // When C == (C2 & Mask) simplifies to (X & Mask).
+  // This pattern appears in alignment calculations.
+  {
+    const APInt *ConstC, *ConstC2, *MaskVal;
+    Value *X;
+    if (match(Op0, m_APInt(ConstC)) &&
+        match(Op1, m_And(m_Sub(m_APInt(ConstC2), m_Value(X)), m_APInt(MaskVal)))) {
+      // Check that MaskVal is a mask that clears low bits (i.e., ~MaskVal is a low-bit mask).
+      APInt NotMask = ~*MaskVal;
+      if ((NotMask + 1).isPowerOf2()) {
+        APInt C2Masked = *ConstC2 & *MaskVal;
+        APInt NewC = *ConstC - C2Masked;
+        Value *And = Builder.CreateAnd(X, ConstantInt::get(Ty, *MaskVal));
+        if (NewC.isZero())
+          return replaceInstUsesWith(I, And);
+        // If NewC is not zero, emit add.
+        return BinaryOperator::CreateAdd(And, ConstantInt::get(Ty, NewC));
+      }
+    }
+  }
+
   if (Instruction *V =
           canonicalizeCondSignextOfHighBitExtractToSignextHighBitExtract(I))
     return V;
@@ -2301,6 +2324,7 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
   return TryToNarrowDeduceFlags();
 }

+
